INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '3.1', 'knowledge', '{"content":"<b>Recap</b><br>вҖў The <b>Cartesian plane</b> has a horizontal $x$-axis and vertical $y$-axis, crossing at the <b>origin</b> $(0, 0)$.<br>вҖў A point is written as $(x, y)$. The $x$-coordinate comes first.<br>вҖў <b>Four quadrants</b>: Q1 $(+, +)$, Q2 $(-, +)$, Q3 $(-, -)$, Q4 $(+, -)$.<br><br><b>Key Skills</b><br>вҖў Plot and read coordinates in all four quadrants.<br>вҖў Identify coordinates from geometric shapes drawn on axes.","content_zh":"<b>зҹҘиҜҶеӣһйЎҫ</b><br>вҖў <b>з¬ӣеҚЎе°”е№ійқў</b>пјҡж°ҙе№і $x$ иҪҙе’ҢеһӮзӣҙ $y$ иҪҙпјҢдәӨдәҺ<b>еҺҹзӮ№</b> $(0,0)$гҖӮ<br>вҖў зӮ№еҶҷдҪң $(x, y)$пјҢ$x$ еқҗж ҮеңЁеүҚгҖӮ<br>вҖў еӣӣдёӘиұЎйҷҗпјҡQ1 $(+,+)$, Q2 $(-,+)$, Q3 $(-,-)$, Q4 $(+,-)$гҖӮ"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '3.1', 'examples', '{"content":"<b>Worked Example</b> [2 marks]<br>A rectangle has vertices at $A(1, 2)$, $B(5, 2)$, $C(5, 6)$. Find $D$.<br><br><b>Solution:</b><br>$D$ must complete the rectangle: same $x$ as $A$, same $y$ as $C$.<br>$D = (1, 6)$<br><br><b>Exam Tip:</b> Sketch the shape on axes to visualise the missing vertex.","content_zh":"<b>з»Ҹе…ёдҫӢйўҳ</b> [2 еҲҶ]<br>зҹ©еҪўйЎ¶зӮ№ $A(1,2)$, $B(5,2)$, $C(5,6)$пјҢжұӮ $D$гҖӮ<br><br><b>и§Јзӯ”пјҡ</b>$D = (1, 6)$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '3.2', 'knowledge', '{"content":"<b>Recap</b><br>вҖў A linear graph is a straight line. Equation: $y = mx + c$.<br>вҖў To draw: make a table of at least 3 values of $(x, y)$, plot, and join with a ruler.<br>вҖў Special lines: $y = c$ is horizontal; $x = a$ is vertical.<br><br><b>Key Skills</b><br>вҖў Draw lines from equations. Read equations from graphs.<br>вҖў Find where two lines intersect (solve simultaneously).<br><br><b>Exam Tip</b><br>Use 3 points to draw a line вҖ” the third point checks for errors.","content_zh":"<b>зҹҘиҜҶеӣһйЎҫ</b><br>вҖў дёҖж¬ЎеҮҪж•°еӣҫеғҸжҳҜзӣҙзәҝгҖӮ$y = mx + c$гҖӮ<br>вҖў з”»жі•пјҡеҲ—иЎЁжұӮиҮіе°‘3дёӘзӮ№пјҢжҸҸзӮ№иҝһзәҝгҖӮ<br>вҖў зү№ж®Ҡзәҝпјҡ$y = c$ ж°ҙе№іпјӣ$x = a$ еһӮзӣҙгҖӮ<br><br><b>иҖғиҜ•жҠҖе·§</b><br>з”Ё3дёӘзӮ№з”»зәҝпјҢз¬¬3дёӘзӮ№з”ЁдәҺжЈҖйӘҢгҖӮ"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '3.2', 'examples', '{"content":"<b>Worked Example</b> [3 marks]<br>Draw the graph of $y = 2x - 3$ for $-1 \\leq x \\leq 4$.<br><br><b>Solution:</b><br>$x = -1$: $y = -5$; $x = 0$: $y = -3$; $x = 2$: $y = 1$; $x = 4$: $y = 5$.<br>Plot these points and join with a straight line.<br><br><b>Exam Tip:</b> Always use a ruler for straight-line graphs.","content_zh":"<b>з»Ҹе…ёдҫӢйўҳ</b> [3 еҲҶ]<br>з”» $y = 2x - 3$ еңЁ $-1 \\leq x \\leq 4$ зҡ„еӣҫеғҸгҖӮ<br><br><b>и§Јзӯ”пјҡ</b>д»Је…Ҙ $x = -1, 0, 2, 4$ еҫ— $y = -5, -3, 1, 5$пјҢжҸҸзӮ№з”Ёзӣҙе°әиҝһзәҝгҖӮ"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '3.3', 'knowledge', '{"content":"<b>Recap</b><br>вҖў <b>Gradient</b> (slope) = $\\frac{\\text{rise}}{\\text{run}} = \\frac{y_2 - y_1}{x_2 - x_1}$.<br>вҖў Positive gradient: line goes uphill (left to right).<br>вҖў Negative gradient: line goes downhill.<br>вҖў Zero gradient: horizontal line. Undefined gradient: vertical line.<br>вҖў In $y = mx + c$, $m$ is the gradient.<br><br><b>Key Skills</b><br>вҖў Calculate gradient from two points.<br>вҖў Read gradient from a graph using a right-angled triangle.<br><br><b>Exam Tip</b><br>Pick two points far apart on the line for a more accurate gradient calculation.","content_zh":"<b>зҹҘиҜҶеӣһйЎҫ</b><br>вҖў <b>ж–ңзҺҮ</b> = $\\frac{y_2 - y_1}{x_2 - x_1}$гҖӮ<br>вҖў жӯЈж–ңзҺҮпјҡдёҠеҚҮгҖӮиҙҹж–ңзҺҮпјҡдёӢйҷҚгҖӮйӣ¶ж–ңзҺҮпјҡж°ҙе№ігҖӮжңӘе®ҡд№үпјҡеһӮзӣҙгҖӮ<br>вҖў $y = mx + c$ дёӯ $m$ дёәж–ңзҺҮгҖӮ<br><br><b>иҖғиҜ•жҠҖе·§</b><br>йҖүи·қзҰ»иҫғиҝңзҡ„дёӨзӮ№и®Ўз®—ж–ңзҺҮжӣҙеҮҶзЎ®гҖӮ"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '3.3', 'examples', '{"content":"<b>Worked Example</b> [2 marks]<br>Find the gradient of the line through $(2, 5)$ and $(8, -1)$.<br><br><b>Solution:</b><br>$m = \\frac{-1 - 5}{8 - 2} = \\frac{-6}{6} = -1$<br><br><b>Exam Tip:</b> Be consistent: always subtract in the same order for both coordinates.","content_zh":"<b>з»Ҹе…ёдҫӢйўҳ</b> [2 еҲҶ]<br>жұӮиҝҮ $(2,5)$ е’Ң $(8,-1)$ зҡ„зӣҙзәҝж–ңзҺҮгҖӮ<br><br><b>и§Јзӯ”пјҡ</b>$m = \\frac{-1-5}{8-2} = -1$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '3.4', 'knowledge', '{"content":"<b>Recap</b><br>вҖў <b>Distance</b> between $(x_1, y_1)$ and $(x_2, y_2)$:<br>$d = \\sqrt{(x_2 - x_1)^2 + (y_2 - y_1)^2}$ (Pythagoras on the coordinate plane).<br>вҖў <b>Midpoint</b>: $M = \\left(\\frac{x_1 + x_2}{2}, \\frac{y_1 + y_2}{2}\\right)$.<br><br><b>Key Skills</b><br>вҖў Calculate the exact distance between two points.<br>вҖў Find the midpoint of a line segment.<br><br><b>Exam Tip</b><br>Leave answers in surd form if the question says \"exact value\".","content_zh":"<b>зҹҘиҜҶеӣһйЎҫ</b><br>вҖў <b>дёӨзӮ№и·қзҰ»</b>пјҡ$d = \\sqrt{(x_2-x_1)^2 + (y_2-y_1)^2}$гҖӮ<br>вҖў <b>дёӯзӮ№</b>пјҡ$M = \\left(\\frac{x_1+x_2}{2}, \\frac{y_1+y_2}{2}\\right)$гҖӮ<br><br><b>иҖғиҜ•жҠҖе·§</b><br>йўҳзӣ®иҰҒжұӮ\"зІҫзЎ®еҖј\"ж—¶з”Ёж №ејҸиЎЁзӨәгҖӮ"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '3.4', 'examples', '{"content":"<b>Worked Example</b> [3 marks]<br>Find the distance and midpoint of $A(1, 3)$ and $B(7, 11)$.<br><br><b>Solution:</b><br>$d = \\sqrt{(7-1)^2 + (11-3)^2} = \\sqrt{36 + 64} = \\sqrt{100} = 10$<br>$M = \\left(\\frac{1+7}{2}, \\frac{3+11}{2}\\right) = (4, 7)$","content_zh":"<b>з»Ҹе…ёдҫӢйўҳ</b> [3 еҲҶ]<br>жұӮ $A(1,3)$ е’Ң $B(7,11)$ зҡ„и·қзҰ»е’ҢдёӯзӮ№гҖӮ<br><br><b>и§Јзӯ”пјҡ</b>$d = \\sqrt{36+64} = 10$пјҢ$M = (4, 7)$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '3.5', 'knowledge', '{"content":"<b>Recap</b><br>вҖў <b>Slope-intercept form</b>: $y = mx + c$ (gradient $m$, $y$-intercept $c$).<br>вҖў Given gradient and a point: $y - y_1 = m(x - x_1)$.<br>вҖў Given two points: find $m$ first, then use point-slope form.<br><br><b>Key Skills</b><br>вҖў Write the equation of a line from a graph.<br>вҖў Write the equation from gradient + point, or two points.<br>вҖў Rearrange between $y = mx + c$ and $ax + by = c$.<br><br><b>Exam Tip</b><br>If given a graph, read off the $y$-intercept and calculate the gradient to write $y = mx + c$.","content_zh":"<b>зҹҘиҜҶеӣһйЎҫ</b><br>вҖў $y = mx + c$пјҡж–ңзҺҮ $m$пјҢ$y$ жҲӘи·қ $c$гҖӮ<br>вҖў е·ІзҹҘж–ңзҺҮе’ҢдёҖзӮ№пјҡ$y - y_1 = m(x - x_1)$гҖӮ<br>вҖў е·ІзҹҘдёӨзӮ№пјҡе…ҲжұӮ $m$пјҢеҶҚз”ЁзӮ№ж–ңејҸгҖӮ<br><br><b>иҖғиҜ•жҠҖе·§</b><br>д»ҺеӣҫдёӯиҜ»еҮә $y$ жҲӘи·қе’Ңж–ңзҺҮеҚіеҸҜеҶҷеҮәж–№зЁӢгҖӮ"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '3.5', 'examples', '{"content":"<b>Worked Example</b> [3 marks]<br>Find the equation of the line through $(2, 1)$ and $(6, 9)$.<br><br><b>Solution:</b><br>$m = \\frac{9-1}{6-2} = \\frac{8}{4} = 2$<br>$y - 1 = 2(x - 2)$<br>$y = 2x - 3$","content_zh":"<b>з»Ҹе…ёдҫӢйўҳ</b> [3 еҲҶ]<br>жұӮиҝҮ $(2,1)$ е’Ң $(6,9)$ зҡ„зӣҙзәҝж–№зЁӢгҖӮ<br><br><b>и§Јзӯ”пјҡ</b>$m = 2$пјҢ$y - 1 = 2(x-2)$пјҢ$y = 2x - 3$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '3.6', 'knowledge', '{"content":"<b>Recap</b><br>вҖў <b>Parallel lines</b> have the SAME gradient.<br>вҖў If $L_1$ has gradient $m$, any line parallel to it also has gradient $m$.<br>вҖў To find a parallel line through a given point: use $y - y_1 = m(x - x_1)$ with the same $m$.<br><br><b>Exam Tip</b><br>When asked \"find the equation of the line parallel to $y = 3x + 1$ through $(2, 5)$\", the gradient is 3.","content_zh":"<b>зҹҘиҜҶеӣһйЎҫ</b><br>вҖў <b>е№іиЎҢзәҝ</b>ж–ңзҺҮзӣёеҗҢгҖӮ<br>вҖў жұӮиҝҮжҹҗзӮ№зҡ„е№іиЎҢзәҝпјҡз”ЁзӣёеҗҢж–ңзҺҮ $m$ д»Је…ҘзӮ№ж–ңејҸгҖӮ<br><br><b>иҖғиҜ•жҠҖе·§</b><br>\"е№іиЎҢдәҺ $y = 3x+1$\" вҶ’ ж–ңзҺҮдёә 3гҖӮ"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '3.6', 'examples', '{"content":"<b>Worked Example</b> [2 marks]<br>Find the equation of the line parallel to $y = -2x + 5$ that passes through $(3, 1)$.<br><br><b>Solution:</b><br>Gradient $m = -2$ (same as the given line).<br>$y - 1 = -2(x - 3)$<br>$y = -2x + 7$","content_zh":"<b>з»Ҹе…ёдҫӢйўҳ</b> [2 еҲҶ]<br>жұӮе№іиЎҢдәҺ $y = -2x+5$гҖҒиҝҮ $(3,1)$ зҡ„зӣҙзәҝж–№зЁӢгҖӮ<br><br><b>и§Јзӯ”пјҡ</b>$m = -2$пјҢ$y - 1 = -2(x-3)$пјҢ$y = -2x + 7$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '3.7', 'knowledge', '{"content":"<b>Extended Only</b><br><br><b>Recap</b><br>вҖў <b>Perpendicular lines</b> meet at 90В°.<br>вҖў If one line has gradient $m$, a perpendicular line has gradient $-\\frac{1}{m}$.<br>вҖў Product of gradients of perpendicular lines = $-1$: $m_1 \\times m_2 = -1$.<br><br><b>Key Skills</b><br>вҖў Find the gradient of a perpendicular line.<br>вҖў Write the equation of a perpendicular through a given point.<br>вҖў Find the perpendicular bisector of a line segment (passes through midpoint, perpendicular gradient).<br><br><b>Watch Out!</b><br>The negative reciprocal of $\\frac{2}{3}$ is $-\\frac{3}{2}$, not $-\\frac{2}{3}$.","content_zh":"<b>д»… Extended</b><br><br><b>зҹҘиҜҶеӣһйЎҫ</b><br>вҖў <b>еһӮзӣҙзәҝ</b>жҲҗ 90В°гҖӮ<br>вҖў ж–ңзҺҮ $m$ зҡ„еһӮзӣҙзәҝж–ңзҺҮдёә $-\\frac{1}{m}$гҖӮ<br>вҖў еһӮзӣҙзәҝж–ңзҺҮд№Ӣз§Ҝ = $-1$гҖӮ<br>вҖў <b>еһӮзӣҙе№іеҲҶзәҝ</b>пјҡиҝҮдёӯзӮ№дё”ж–ңзҺҮдёәиҙҹеҖ’ж•°гҖӮ<br><br><b>жіЁж„ҸпјҒ</b><br>$\\frac{2}{3}$ зҡ„иҙҹеҖ’ж•°жҳҜ $-\\frac{3}{2}$пјҢдёҚжҳҜ $-\\frac{2}{3}$гҖӮ"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '3.7', 'examples', '{"content":"<b>Worked Example</b> [3 marks]<br>Line $L$ passes through $A(1, 4)$ and $B(5, 2)$. Find the equation of the perpendicular bisector of $AB$.<br><br><b>Solution:</b><br>Midpoint: $M = (3, 3)$<br>Gradient of $AB$: $m = \\frac{2-4}{5-1} = -\\frac{1}{2}$<br>Perpendicular gradient: $m_{\\perp} = 2$<br>$y - 3 = 2(x - 3)$<br>$y = 2x - 3$<br><br><b>Exam Tip:</b> Perpendicular bisector = midpoint + negative reciprocal gradient.","content_zh":"<b>з»Ҹе…ёдҫӢйўҳ</b> [3 еҲҶ]<br>зӣҙзәҝ $L$ иҝҮ $A(1,4)$ е’Ң $B(5,2)$пјҢжұӮ $AB$ зҡ„еһӮзӣҙе№іеҲҶзәҝж–№зЁӢгҖӮ<br><br><b>и§Јзӯ”пјҡ</b>дёӯзӮ№ $(3,3)$пјҢ$AB$ ж–ңзҺҮ $-\\frac{1}{2}$пјҢеһӮзӣҙж–ңзҺҮ $2$<br>$y - 3 = 2(x-3)$пјҢ$y = 2x - 3$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '3.1', 'knowledge', '{"content":"<b>Recap</b><br>вҖў A <b>sequence</b> is an ordered list of numbers following a pattern.<br>вҖў <b>Term-to-term rule</b>: how to get from one term to the next.<br>вҖў <b>$n$th term</b> (position-to-term): $T_n$ gives any term directly.<br>вҖў <b>Arithmetic</b>: constant difference $d$. $T_n = a + (n-1)d$ or $T_n = dn + (a - d)$.<br><br><b>Higher Only</b><br>вҖў <b>Quadratic sequences</b>: second differences are constant. $T_n = an^2 + bn + c$.<br>вҖў <b>Geometric sequences</b>: constant ratio $r$. $T_n = ar^{n-1}$.<br>вҖў <b>Fibonacci-type</b>: each term = sum of previous two.<br><br><b>Exam Tip</b><br>Always check your formula with $n = 1, 2, 3$.","content_zh":"<b>зҹҘиҜҶеӣһйЎҫ</b><br>вҖў <b>зӯүе·®ж•°еҲ—</b>пјҡе…¬е·® $d$ жҒ’е®ҡпјҢ$T_n = dn + (a-d)$гҖӮ<br><br><b>д»… Higher</b><br>вҖў <b>дәҢж¬Ўж•°еҲ—</b>пјҡдәҢйҳ¶е·®жҒ’е®ҡпјҢ$T_n = an^2 + bn + c$гҖӮ<br>вҖў <b>зӯүжҜ”ж•°еҲ—</b>пјҡе…¬жҜ” $r$пјҢ$T_n = ar^{n-1}$гҖӮ<br><br><b>иҖғиҜ•жҠҖе·§</b><br>з”Ё $n = 1, 2, 3$ д»Је…ҘжЈҖйӘҢе…¬ејҸгҖӮ"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '3.1', 'examples', '{"content":"<b>Worked Example 1</b> [2 marks]<br>Find the $n$th term of $7, 11, 15, 19, ...$<br><br><b>Solution:</b><br>$d = 4$, $T_n = 4n + 3$. Check: $T_1 = 7$ вң“<br><br><b>Worked Example 2</b> (Higher) [4 marks]<br>Find the $n$th term of $2, 8, 18, 32, 50, ...$<br><br><b>Solution:</b><br>1st diff: $6, 10, 14, 18$. 2nd diff: $4, 4, 4$ вҶ’ $a = 2$.<br>$T_n = 2n^2 + bn + c$.<br>$n = 1$: $2 + b + c = 2$ вҶ’ $b + c = 0$.<br>$n = 2$: $8 + 2b + c = 8$ вҶ’ $2b + c = 0$.<br>$b = 0, c = 0$. $T_n = 2n^2$.","content_zh":"<b>з»Ҹе…ёдҫӢйўҳ 1</b> [2 еҲҶ]<br>жұӮ $7, 11, 15, 19, ...$ зҡ„йҖҡйЎ№гҖӮ<br><br><b>и§Јзӯ”пјҡ</b>$d = 4$пјҢ$T_n = 4n + 3$<br><br><b>з»Ҹе…ёдҫӢйўҳ 2</b>пјҲHigherпјү[4 еҲҶ]<br>жұӮ $2, 8, 18, 32, 50, ...$ зҡ„йҖҡйЎ№гҖӮ<br><br><b>и§Јзӯ”пјҡ</b>дәҢйҳ¶е·® = 4пјҢ$a = 2$пјҢи§Јеҫ— $T_n = 2n^2$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '3.2', 'knowledge', '{"content":"<b>Higher Only</b><br><br><b>Recap</b><br>вҖў <b>Function notation</b>: $f(x) = 2x + 3$ means \"the function $f$ maps $x$ to $2x + 3$\".<br>вҖў $f(5) = 2(5) + 3 = 13$.<br>вҖў <b>Composite functions</b>: $fg(x) = f(g(x))$. Do $g$ first, then $f$.<br>вҖў <b>Inverse functions</b>: $f^{-1}(x)$ undoes $f$. Swap $x$ and $y$, then rearrange.<br>вҖў $ff^{-1}(x) = f^{-1}f(x) = x$.<br>вҖў The graph of $f^{-1}$ is the reflection of $f$ in $y = x$.<br><br><b>Watch Out!</b><br>$fg(x) \\neq gf(x)$ вҖ” composition is NOT commutative.","content_zh":"<b>д»… Higher</b><br><br><b>зҹҘиҜҶеӣһйЎҫ</b><br>вҖў еҮҪж•°з¬ҰеҸ·пјҡ$f(x) = 2x + 3$гҖӮ<br>вҖў еӨҚеҗҲеҮҪж•°пјҡ$fg(x) = f(g(x))$пјҢе…Ҳ $g$ еҗҺ $f$гҖӮ<br>вҖў еҸҚеҮҪж•°пјҡ$f^{-1}(x)$пјҢдәӨжҚў $x, y$ еҗҺи§ЈеҮәгҖӮ<br>вҖў $f^{-1}$ еӣҫеғҸжҳҜ $f$ е…ідәҺ $y = x$ зҡ„еҜ№з§°гҖӮ<br><br><b>жіЁж„ҸпјҒ</b>$fg(x) \\neq gf(x)$гҖӮ"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '3.2', 'examples', '{"content":"<b>Worked Example</b> [5 marks]<br>$f(x) = 3x - 1$, $g(x) = x^2 + 4$.<br>(a) Find $gf(2)$. (b) Find $fg(x)$. (c) Find $f^{-1}(x)$.<br><br><b>Solution:</b><br>(a) $f(2) = 5$, $g(5) = 29$. So $gf(2) = 29$.<br>(b) $fg(x) = f(x^2 + 4) = 3(x^2 + 4) - 1 = 3x^2 + 11$.<br>(c) $y = 3x - 1$ вҶ’ $x = 3y - 1$ вҶ’ $y = \\frac{x + 1}{3}$.<br>$f^{-1}(x) = \\frac{x + 1}{3}$.","content_zh":"<b>з»Ҹе…ёдҫӢйўҳ</b> [5 еҲҶ]<br>$f(x) = 3x-1$, $g(x) = x^2+4$гҖӮ<br>(a) $gf(2)$ (b) $fg(x)$ (c) $f^{-1}(x)$<br><br><b>и§Јзӯ”пјҡ</b>(a) $f(2)=5, g(5)=29$<br>(b) $3x^2 + 11$<br>(c) $f^{-1}(x) = \\frac{x+1}{3}$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '3.3', 'knowledge', '{"content":"<b>Recap</b><br>вҖў <b>Linear</b>: $y = mx + c$. Straight line.<br>вҖў <b>Quadratic</b>: $y = ax^2 + bx + c$. Parabola.<br>вҖў <b>Cubic</b>: $y = ax^3 + ...$. S-shaped.<br>вҖў <b>Reciprocal</b>: $y = \\frac{a}{x}$. Hyperbola with asymptotes along axes.<br><br><b>Key Skills</b><br>вҖў Plot graphs from tables of values.<br>вҖў Find solutions graphically (intersections with $x$-axis or other curves).<br>вҖў Read off and interpret gradients, intercepts, and turning points.<br><br><b>Higher Only</b><br>вҖў <b>Exponential</b>: $y = a^x$ (growth), $y = a^{-x}$ (decay).<br>вҖў <b>Trig graphs</b>: $\\sin x$, $\\cos x$, $\\tan x$ with period and amplitude.<br>вҖў <b>Transformations</b>: $f(x) + a$ (up), $f(x + a)$ (left), $af(x)$ (vertical stretch), $f(ax)$ (horizontal compress).<br>вҖў <b>Tangent to a curve</b>: draw tangent, calculate gradient.","content_zh":"<b>зҹҘиҜҶеӣһйЎҫ</b><br>вҖў дёҖж¬ЎгҖҒдәҢж¬ЎгҖҒдёүж¬ЎгҖҒеҸҚжҜ”дҫӢеҮҪж•°еӣҫеғҸгҖӮ<br><br><b>д»… Higher</b><br>вҖў жҢҮж•°еҮҪж•°гҖҒдёүи§’еҮҪж•°еӣҫеғҸгҖӮ<br>вҖў еӣҫеғҸеҸҳжҚўпјҡ$f(x)+a$ дёҠз§»пјҢ$f(x+a)$ е·Ұз§»пјҢ$af(x)$ зәөеҗ‘жӢүдјёпјҢ$f(ax)$ жЁӘеҗ‘еҺӢзј©гҖӮ<br>вҖў з”»еҲҮзәҝжұӮж–ңзҺҮгҖӮ"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '3.3', 'examples', '{"content":"<b>Worked Example</b> [4 marks]<br>The graph of $y = f(x)$ has a maximum at $(2, 5)$. Write down the coordinates of the maximum of:<br>(a) $y = f(x) + 3$ &nbsp;&nbsp; (b) $y = f(x - 4)$ &nbsp;&nbsp; (c) $y = -f(x)$<br><br><b>Solution:</b><br>(a) Shift up 3: $(2, 8)$<br>(b) Shift right 4: $(6, 5)$<br>(c) Reflect in $x$-axis: $(2, -5)$ вҖ” this becomes a <b>minimum</b>.<br><br><b>Exam Tip:</b> $f(x - a)$ shifts RIGHT, $f(x + a)$ shifts LEFT. The sign is opposite to what you might expect.","content_zh":"<b>з»Ҹе…ёдҫӢйўҳ</b> [4 еҲҶ]<br>$y = f(x)$ жңҖеӨ§еҖјеңЁ $(2,5)$пјҢжұӮдёӢеҲ—еҮҪж•°жңҖеӨ§еҖјеқҗж Үпјҡ<br>(a) $y = f(x)+3$ (b) $y = f(x-4)$ (c) $y = -f(x)$<br><br><b>и§Јзӯ”пјҡ</b>(a) $(2, 8)$<br>(b) $(6, 5)$<br>(c) $(2, -5)$пјҲеҸҳдёәжңҖе°ҸеҖјпјү"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '3.4', 'knowledge', '{"content":"<b>Higher Only</b><br><br><b>Recap</b><br>вҖў <b>Differentiation</b>: if $y = ax^n$, then $\\frac{dy}{dx} = anx^{n-1}$.<br>вҖў $\\frac{dy}{dx}$ gives the <b>gradient of the curve</b> at any point.<br>вҖў <b>Turning points</b>: set $\\frac{dy}{dx} = 0$.<br>вҖў Nature: $\\frac{d^2y}{dx^2} > 0$ вҶ’ min; $\\frac{d^2y}{dx^2} < 0$ вҶ’ max.<br><br><b>Key Skills</b><br>вҖў Differentiate polynomials.<br>вҖў Find and classify turning points.<br>вҖў Find the equation of a tangent at a given point.<br><br><b>Exam Tip</b><br>For tangent equation: find $\\frac{dy}{dx}$ at the point (= gradient $m$), then use $y - y_1 = m(x - x_1)$.","content_zh":"<b>д»… Higher</b><br><br><b>зҹҘиҜҶеӣһйЎҫ</b><br>вҖў $y = ax^n$ вҶ’ $\\frac{dy}{dx} = anx^{n-1}$гҖӮ<br>вҖў иҪ¬жҠҳзӮ№пјҡд»Ө $\\frac{dy}{dx} = 0$гҖӮ<br>вҖў $\\frac{d^2y}{dx^2} > 0$ жңҖе°ҸеҖјпјӣ$< 0$ жңҖеӨ§еҖјгҖӮ<br><br><b>иҖғиҜ•жҠҖе·§</b><br>жұӮеҲҮзәҝж–№зЁӢпјҡе…ҲжұӮиҜҘзӮ№ж–ңзҺҮ $m$пјҢеҶҚз”ЁзӮ№ж–ңејҸгҖӮ"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '3.4', 'examples', '{"content":"<b>Worked Example</b> [5 marks]<br>$y = x^3 - 6x^2 + 9x + 2$. Find the turning points and determine their nature.<br><br><b>Solution:</b><br>$\\frac{dy}{dx} = 3x^2 - 12x + 9 = 3(x^2 - 4x + 3) = 3(x-1)(x-3)$<br>Set $= 0$: $x = 1$ or $x = 3$.<br><br>$\\frac{d^2y}{dx^2} = 6x - 12$<br>At $x = 1$: $6 - 12 = -6 < 0$ вҶ’ <b>maximum</b>. $y = 1 - 6 + 9 + 2 = 6$.<br>At $x = 3$: $18 - 12 = 6 > 0$ вҶ’ <b>minimum</b>. $y = 27 - 54 + 27 + 2 = 2$.<br><br>Max $(1, 6)$, Min $(3, 2)$.","content_zh":"<b>з»Ҹе…ёдҫӢйўҳ</b> [5 еҲҶ]<br>жұӮ $y = x^3 - 6x^2 + 9x + 2$ зҡ„иҪ¬жҠҳзӮ№е№¶еҲӨж–ӯжҖ§иҙЁгҖӮ<br><br><b>и§Јзӯ”пјҡ</b>$\\frac{dy}{dx} = 3(x-1)(x-3) = 0$<br>$x = 1$пјҡжңҖеӨ§еҖј $(1, 6)$пјӣ$x = 3$пјҡжңҖе°ҸеҖј $(3, 2)$гҖӮ"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
